function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'monthly');
const SOURCE_URL = 'https://apisidra.ibge.gov.br/values/t/6588/n1/1/n3/11,29,31,32/v/35,36,109,216/p/last%2012/c48/39454,39455/f/a?formato=json';
const PRODUCT_MAP = {
  '39454': { key: 'arabica', name: 'Cafe arabica' },
  '39455': { key: 'canephora', name: 'Cafe canephora' }
};
const VARIABLE_MAP = {
  '35': { key: 'production_tons', name: 'Produção' },
  '36': { key: 'yield_kg_per_ha', name: 'Rendimento médio' },
  '109': { key: 'planted_area_ha', name: 'Área plantada' },
  '216': { key: 'harvested_area_ha', name: 'Área colhida' }
};
const GEO_META = {
  '1': { code: '1', name: 'Brasil', level: 'BR' },
  '31': { code: '31', name: 'Minas Gerais', level: 'UF' },
  '32': { code: '32', name: 'Espírito Santo', level: 'UF' },
  '29': { code: '29', name: 'Bahia', level: 'UF' },
  '11': { code: '11', name: 'Rondônia', level: 'UF' }
};
const STATE_CODES = ['31', '32', '29', '11'];

function round(value, decimals = 4) {
  if (value === null || value === undefined || Number.isNaN(value)) return null;
  return Number(Number(value).toFixed(decimals));
}

function parseValue(value) {
  if (value === null || value === undefined || value === '') return null;
  const normalized = String(value).trim();
  if (normalized === '-' || normalized === '0') return 0;
  if (normalized === '..' || normalized === '...' || normalized === 'X') return null;
  if (/^[A-WY-Z]$/i.test(normalized)) return null;
  const numeric = Number(normalized.replace(/\./g, '').replace(',', '.'));
  return Number.isNaN(numeric) ? null : numeric;
}

function safeDivide(numerator, denominator, decimals = 6) {
  if (numerator === null || denominator === null || denominator === 0) return null;
  return round(numerator / denominator, decimals);
}

function pctChange(current, previous, decimals = 4) {
  if (current === null || previous === null || previous === 0) return null;
  return round(((current - previous) / previous) * 100, decimals);
}

const rawRows = [];
for (const item of $input.all()) {
  if (Array.isArray(item.json)) rawRows.push(...item.json);
  else if (Array.isArray(item.json.body)) rawRows.push(...item.json.body);
  else if (item.json && typeof item.json === 'object' && Object.prototype.hasOwnProperty.call(item.json, 'V')) rawRows.push(item.json);
}

const rows = rawRows
  .filter((row) => row && row.V !== 'Valor' && PRODUCT_MAP[row.D4C] && VARIABLE_MAP[row.D2C] && GEO_META[row.D1C])
  .map((row) => ({
    geo_code: row.D1C,
    geo_name: GEO_META[row.D1C].name,
    geo_level: GEO_META[row.D1C].level,
    variable_code: row.D2C,
    variable_key: VARIABLE_MAP[row.D2C].key,
    variable_name: VARIABLE_MAP[row.D2C].name,
    period_code: row.D3C,
    period_label: row.D3N,
    product_code: row.D4C,
    product_key: PRODUCT_MAP[row.D4C].key,
    product_name: PRODUCT_MAP[row.D4C].name,
    unit_name: row.MN,
    value: parseValue(row.V)
  }));

if (!rows.length) {
  throw new Error('IBGE SIDRA returned no valid rows for the requested coffee query');
}

const periodLabels = {};
const index = new Map();
for (const row of rows) {
  periodLabels[row.period_code] = row.period_label;
  const key = `${row.period_code}|${row.geo_code}|${row.product_code}`;
  const current = index.get(key) || {
    period_code: row.period_code,
    period_label: row.period_label,
    geo_code: row.geo_code,
    geo_name: row.geo_name,
    geo_level: row.geo_level,
    product_code: row.product_code,
    product_key: row.product_key,
    product_name: row.product_name
  };
  current[row.variable_key] = row.value;
  index.set(key, current);
}

const periods = Array.from(new Set(rows.map((row) => row.period_code))).sort();
if (!periods.length) throw new Error('IBGE SIDRA returned no periods');
const latestPeriod = periods[periods.length - 1];
const comparisonPeriod = periods[0];
const previousPeriod = periods.length > 1 ? periods[periods.length - 2] : null;

function getEntry(periodCode, geoCode, productCode) {
  const record = index.get(`${periodCode}|${geoCode}|${productCode}`) || {};
  return {
    production_tons: record.production_tons ?? null,
    yield_kg_per_ha: record.yield_kg_per_ha ?? null,
    planted_area_ha: record.planted_area_ha ?? null,
    harvested_area_ha: record.harvested_area_ha ?? null
  };
}

function buildGeoSnapshot(periodCode, geoCode) {
  const arabica = getEntry(periodCode, geoCode, '39454');
  const canephora = getEntry(periodCode, geoCode, '39455');
  const totalProduction = (arabica.production_tons ?? 0) + (canephora.production_tons ?? 0);
  return {
    geo_code: geoCode,
    geo_name: GEO_META[geoCode].name,
    geo_level: GEO_META[geoCode].level,
    arabica,
    canephora,
    total_production_tons: totalProduction ? round(totalProduction, 0) : 0
  };
}

const nationalLatest = buildGeoSnapshot(latestPeriod, '1');
const nationalComparison = buildGeoSnapshot(comparisonPeriod, '1');
const nationalPreviousMonth = previousPeriod ? buildGeoSnapshot(previousPeriod, '1') : null;
const stateFocusLatest = STATE_CODES.map((geoCode) => buildGeoSnapshot(latestPeriod, geoCode));
const stateFocusComparison = Object.fromEntries(STATE_CODES.map((geoCode) => [geoCode, buildGeoSnapshot(comparisonPeriod, geoCode)]));

const latestTotal = nationalLatest.total_production_tons;
const comparisonTotal = nationalComparison.total_production_tons;
const arabicaSharePct = safeDivide(nationalLatest.arabica.production_tons, latestTotal);
const canephoraSharePct = safeDivide(nationalLatest.canephora.production_tons, latestTotal);

const stateProductionSharesPct = {};
const stateProductionChangesPct = {};
for (const stateCode of STATE_CODES) {
  const latestState = stateFocusLatest.find((entry) => entry.geo_code === stateCode);
  const previousState = stateFocusComparison[stateCode];
  stateProductionSharesPct[stateCode] = {
    geo_name: GEO_META[stateCode].name,
    arabica_share_of_brazil_pct: latestState ? round((safeDivide(latestState.arabica.production_tons, nationalLatest.arabica.production_tons) || 0) * 100, 4) : null,
    canephora_share_of_brazil_pct: latestState ? round((safeDivide(latestState.canephora.production_tons, nationalLatest.canephora.production_tons) || 0) * 100, 4) : null
  };
  stateProductionChangesPct[stateCode] = {
    geo_name: GEO_META[stateCode].name,
    arabica_production_change_pct: latestState ? pctChange(latestState.arabica.production_tons, previousState.arabica.production_tons) : null,
    canephora_production_change_pct: latestState ? pctChange(latestState.canephora.production_tons, previousState.canephora.production_tons) : null,
    total_production_change_pct: latestState ? pctChange(latestState.total_production_tons, previousState.total_production_tons) : null
  };
}

const recentSeries = periods.map((periodCode) => {
  const brazil = buildGeoSnapshot(periodCode, '1');
  return {
    period_code: periodCode,
    period_label: periodLabels[periodCode],
    arabica_production_tons: brazil.arabica.production_tons,
    canephora_production_tons: brazil.canephora.production_tons,
    total_production_tons: brazil.total_production_tons,
    arabica_yield_kg_per_ha: brazil.arabica.yield_kg_per_ha,
    canephora_yield_kg_per_ha: brazil.canephora.yield_kg_per_ha,
    arabica_harvested_area_ha: brazil.arabica.harvested_area_ha,
    canephora_harvested_area_ha: brazil.canephora.harvested_area_ha
  };
});

const arabicaProductionChangePct = pctChange(nationalLatest.arabica.production_tons, nationalComparison.arabica.production_tons);
const canephoraProductionChangePct = pctChange(nationalLatest.canephora.production_tons, nationalComparison.canephora.production_tons);
const totalProductionChangePct = pctChange(latestTotal, comparisonTotal);
const arabicaYieldChangePct = pctChange(nationalLatest.arabica.yield_kg_per_ha, nationalComparison.arabica.yield_kg_per_ha);
const momArabicaProductionChangePct = nationalPreviousMonth ? pctChange(nationalLatest.arabica.production_tons, nationalPreviousMonth.arabica.production_tons) : null;
const momCanephoraProductionChangePct = nationalPreviousMonth ? pctChange(nationalLatest.canephora.production_tons, nationalPreviousMonth.canephora.production_tons) : null;
const momTotalProductionChangePct = nationalPreviousMonth ? pctChange(nationalLatest.total_production_tons, nationalPreviousMonth.total_production_tons) : null;
const momArabicaYieldChangePct = nationalPreviousMonth ? pctChange(nationalLatest.arabica.yield_kg_per_ha, nationalPreviousMonth.arabica.yield_kg_per_ha) : null;
const momCanephoraYieldChangePct = nationalPreviousMonth ? pctChange(nationalLatest.canephora.yield_kg_per_ha, nationalPreviousMonth.canephora.yield_kg_per_ha) : null;
const canephoraYieldChangePct = pctChange(nationalLatest.canephora.yield_kg_per_ha, nationalComparison.canephora.yield_kg_per_ha);

const ruleBasedFlags = [];
if (arabicaProductionChangePct !== null && arabicaProductionChangePct >= 5) ruleBasedFlags.push('arabica_output_rising');
if (arabicaProductionChangePct !== null && arabicaProductionChangePct <= -5) ruleBasedFlags.push('arabica_output_falling');
if (canephoraProductionChangePct !== null && canephoraProductionChangePct >= 5) ruleBasedFlags.push('canephora_output_rising');
if (canephoraProductionChangePct !== null && canephoraProductionChangePct <= -5) ruleBasedFlags.push('canephora_output_falling');
if ((stateProductionSharesPct['31']?.arabica_share_of_brazil_pct ?? 0) >= 70) ruleBasedFlags.push('minas_gerais_dominates_arabica');
if ((stateProductionSharesPct['32']?.canephora_share_of_brazil_pct ?? 0) >= 50) ruleBasedFlags.push('espirito_santo_dominates_canephora');
if ((stateProductionChangesPct['29']?.canephora_production_change_pct ?? 0) >= 5) ruleBasedFlags.push('bahia_canephora_rising');
if ((stateProductionChangesPct['11']?.canephora_production_change_pct ?? 0) >= 5) ruleBasedFlags.push('rondonia_canephora_rising');
if (arabicaYieldChangePct !== null && arabicaYieldChangePct <= -5) ruleBasedFlags.push('arabica_yield_softening');
if (canephoraYieldChangePct !== null && canephoraYieldChangePct <= -5) ruleBasedFlags.push('canephora_yield_softening');

let movementLabel = 'mixed';
if (totalProductionChangePct !== null && totalProductionChangePct >= 5) movementLabel = 'supply_expanding';
else if (totalProductionChangePct !== null && totalProductionChangePct <= -5) movementLabel = 'supply_tightening';
else if ((stateProductionSharesPct['31']?.arabica_share_of_brazil_pct ?? 0) >= 70 || (stateProductionSharesPct['32']?.canephora_share_of_brazil_pct ?? 0) >= 50) movementLabel = 'regional_shift';


const fallbackSummaryEn = `Latest IBGE LSPA coffee estimate for ${periodLabels[latestPeriod]} shows Brazil at ${round(latestTotal, 0)} tons, with arabica at ${round(nationalLatest.arabica.production_tons, 0)} tons and canephora at ${round(nationalLatest.canephora.production_tons, 0)} tons. Compared with ${periodLabels[comparisonPeriod]}, total production changed by ${totalProductionChangePct === null ? 'n/a' : `${totalProductionChangePct.toFixed(4)}%`}, while Minas Gerais remained dominant in arabica and Espírito Santo remained dominant in canephora.`;

return [{
  json: {
    source: 'IBGE_SIDRA_LSPA',
    source_format: 'json_api',
    source_url: SOURCE_URL,
    source_descriptor_url: 'https://apisidra.ibge.gov.br/DescritoresTabela/t/6588',
    country: 'BR',
    macroarea: 'colture',
    dataset: 'LSPA',
    table_id: 6588,
    classification_id: 48,
    product_codes: { arabica: '39454', canephora: '39455' },
    focus_states: STATE_CODES.map((code) => GEO_META[code]),
    collected_at: now,
    collected_period: _collectedPeriod,
        latest_period_code: latestPeriod,
    latest_period_label: periodLabels[latestPeriod],
    comparison_period_code: comparisonPeriod,
    comparison_period_label: periodLabels[comparisonPeriod],
    national_latest: nationalLatest,
    national_comparison: nationalComparison,
    derived_metrics: {
      national_total_production_tons: latestTotal,
      national_arabica_share_pct: arabicaSharePct !== null ? round(arabicaSharePct * 100, 4) : null,
      national_canephora_share_pct: canephoraSharePct !== null ? round(canephoraSharePct * 100, 4) : null,
      national_changes_vs_first_period_pct: {
        total_production_change_pct: totalProductionChangePct,
        arabica_production_change_pct: arabicaProductionChangePct,
        canephora_production_change_pct: canephoraProductionChangePct,
        arabica_yield_change_pct: arabicaYieldChangePct,
        canephora_yield_change_pct: canephoraYieldChangePct
      },
      mom_changes: {
        comparison_period_label: previousPeriod ? periodLabels[previousPeriod] : null,
        total_production_change_pct: momTotalProductionChangePct,
        arabica_production_change_pct: momArabicaProductionChangePct,
        canephora_production_change_pct: momCanephoraProductionChangePct,
        arabica_yield_change_pct: momArabicaYieldChangePct,
        canephora_yield_change_pct: momCanephoraYieldChangePct
      },
      state_production_shares_pct: stateProductionSharesPct,
      state_production_changes_pct: stateProductionChangesPct
    },
    state_focus_latest: stateFocusLatest,
    recent_series: recentSeries,
    movement_label: movementLabel,
signals: Array.from(new Set(ruleBasedFlags)),
    summary_en: fallbackSummaryEn,
    _chart_fields: ["recent_series", "state_focus_latest"]
  }
}];

const raw = ($json.text || '').trim();
const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();
const parsed = JSON.parse(cleaned);
const base = $('IBGE SIDRA Parse').item.json;

return [{
  json: {
    ...base,
    rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
    rule_based_movement_label: base.movement_label || 'mixed',
fallback_summary_en: base.summary_en || '',
    movement_label: parsed.movement_label || base.movement_label || 'mixed',
    signals: Array.isArray(parsed.signals) ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
    summary_en: parsed.summary_en || base.summary_en || ''
  }
}];

const now = new Date().toISOString();
const meta = $('IBGE Parse Signals').item.json;

return [{
  json: {
    source: 'IBGE_SIDRA_LSPA',
    country: 'BR',
    macroarea: 'colture',
    cadenza: 'weekly',
    run_date: now,
    status: 'done',
    completed_at: now,
    report_period: meta.latest_period_code || null,
  },
}];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '04_IBGE_SIDRA',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json }];
